function solve(prices, strategy, k) {
    const n = prices.length;
    let originalProfit = 0;
    for (let i = 0; i < n; i++) {
        originalProfit += strategy[i] * prices[i];
    }

    let maxProfit = originalProfit;
    const halfK = k / 2;

    const prefixZero = new Array(n + 1).fill(0);
    const prefixOne = new Array(n + 1).fill(0);

    for (let i = 0; i < n; i++) {
        prefixZero[i + 1] = prefixZero[i] + (0 - strategy[i]) * prices[i];
        prefixOne[i + 1] = prefixOne[i] + (1 - strategy[i]) * prices[i];
    }

    for (let i = 0; i <= n - k; i++) {
        const j = i + k;
        const firstHalfEnd = i + halfK;
        const delta = (prefixZero[firstHalfEnd] - prefixZero[i]) + (prefixOne[j] - prefixOne[firstHalfEnd]);
        const currentProfit = originalProfit + delta;
        if (currentProfit > maxProfit) {
            maxProfit = currentProfit;
        }
    }

    return maxProfit;
}
